4611 /// Try to find a partition of the aggregate type passed in for a given
4612 /// offset and size.
4613 ///
4614 /// This recurses through the aggregate type and tries to compute a subtype
4615 /// based on the offset and size. When the offset and size span a sub-section
4616 /// of an array, it will even compute a new array type for that sub-section,
4617 /// and the same for structs.
4618 ///
4619 /// Note that this routine is very strict and tries to find a partition of the
4620 /// type which produces the *exact* right offset and size. It is not forgiving
4621 /// when the size or offset cause either end of type-based partition to be off.
4622 /// Also, this is a best-effort routine. It is reasonable to give up and not
4623 /// return a type if necessary.
4624 static Type *getTypePartition(const DataLayout &DL, Type *Ty, uint64_t Offset,
4625                               uint64_t Size) {
4626   if (Offset == 0 && DL.getTypeAllocSize(Ty).getFixedValue() == Size)
4627     return stripAggregateTypeWrapping(DL, Ty);
4628   if (Offset > DL.getTypeAllocSize(Ty).getFixedValue() ||
4629       (DL.getTypeAllocSize(Ty).getFixedValue() - Offset) < Size)
4630     return nullptr;
4631 
4632   if (isa<ArrayType>(Ty) || isa<VectorType>(Ty)) {
4633     Type *ElementTy;
4634     uint64_t TyNumElements;
4635     if (auto *AT = dyn_cast<ArrayType>(Ty)) {
4636       ElementTy = AT->getElementType();
4637       TyNumElements = AT->getNumElements();
4638     } else {
4639       // FIXME: This isn't right for vectors with non-byte-sized or
4640       // non-power-of-two sized elements.
4641       auto *VT = cast<FixedVectorType>(Ty);
4642       ElementTy = VT->getElementType();
4643       TyNumElements = VT->getNumElements();
4644     }
4645     uint64_t ElementSize = DL.getTypeAllocSize(ElementTy).getFixedValue();
4646     uint64_t NumSkippedElements = Offset / ElementSize;
4647     if (NumSkippedElements >= TyNumElements)
4648       return nullptr;
4649     Offset -= NumSkippedElements * ElementSize;
4650 
4651     // First check if we need to recurse.
4652     if (Offset > 0 || Size < ElementSize) {
4653       // Bail if the partition ends in a different array element.
4654       if ((Offset + Size) > ElementSize)
4655         return nullptr;
4656       // Recurse through the element type trying to peel off offset bytes.
4657       return getTypePartition(DL, ElementTy, Offset, Size);
4658     }
4659     assert(Offset == 0);
4660 
4661     if (Size == ElementSize)
4662       return stripAggregateTypeWrapping(DL, ElementTy);
4663     assert(Size > ElementSize);
4664     uint64_t NumElements = Size / ElementSize;
4665     if (NumElements * ElementSize != Size)
4666       return nullptr;
4667     return ArrayType::get(ElementTy, NumElements);
4668   }
4669 
4670   StructType *STy = dyn_cast<StructType>(Ty);
4671   if (!STy)
4672     return nullptr;
4673 
4674   const StructLayout *SL = DL.getStructLayout(STy);
4675 
4676   if (SL->getSizeInBits().isScalable())
4677     return nullptr;
4678 
4679   if (Offset >= SL->getSizeInBytes())
4680     return nullptr;
4681   uint64_t EndOffset = Offset + Size;
4682   if (EndOffset > SL->getSizeInBytes())
4683     return nullptr;
4684 
4685   unsigned Index = SL->getElementContainingOffset(Offset);
4686   Offset -= SL->getElementOffset(Index);
4687 
4688   Type *ElementTy = STy->getElementType(Index);
4689   uint64_t ElementSize = DL.getTypeAllocSize(ElementTy).getFixedValue();
4690   if (Offset >= ElementSize)
4691     return nullptr; // The offset points into alignment padding.
4692 
4693   // See if any partition must be contained by the element.
4694   if (Offset > 0 || Size < ElementSize) {
4695     if ((Offset + Size) > ElementSize)
4696       return nullptr;
4697     return getTypePartition(DL, ElementTy, Offset, Size);
4698   }
4699   assert(Offset == 0);
4700 
4701   if (Size == ElementSize)
4702     return stripAggregateTypeWrapping(DL, ElementTy);
4703 
4704   StructType::element_iterator EI = STy->element_begin() + Index,
4705                                EE = STy->element_end();
4706   if (EndOffset < SL->getSizeInBytes()) {
4707     unsigned EndIndex = SL->getElementContainingOffset(EndOffset);
4708     if (Index == EndIndex)
4709       return nullptr; // Within a single element and its padding.
4710 
4711     // Don't try to form "natural" types if the elements don't line up with the
4712     // expected size.
4713     // FIXME: We could potentially recurse down through the last element in the
4714     // sub-struct to find a natural end point.
4715     if (SL->getElementOffset(EndIndex) != EndOffset)
4716       return nullptr;
4717 
4718     assert(Index < EndIndex);
4719     EE = STy->element_begin() + EndIndex;
4720   }
4721 
4722   // Try to build up a sub-structure.
4723   StructType *SubTy =
4724       StructType::get(STy->getContext(), ArrayRef(EI, EE), STy->isPacked());
4725   const StructLayout *SubSL = DL.getStructLayout(SubTy);
4726   if (Size != SubSL->getSizeInBytes())
4727     return nullptr; // The sub-struct doesn't have quite the size needed.
4728 
4729   return SubTy;
4730 }
