6997 /// This is a wrapper around getUnderlyingObjects and adds support for basic
6998 /// ptrtoint+arithmetic+inttoptr sequences.
6999 /// It returns false if unidentified object is found in getUnderlyingObjects.
7000 bool llvm::getUnderlyingObjectsForCodeGen(const Value *V,
7001                                           SmallVectorImpl<Value *> &Objects) {
7002   SmallPtrSet<const Value *, 16> Visited;
7003   SmallVector<const Value *, 4> Working(1, V);
7004   do {
7005     V = Working.pop_back_val();
7006 
7007     SmallVector<const Value *, 4> Objs;
7008     getUnderlyingObjects(V, Objs);
7009 
7010     for (const Value *V : Objs) {
7011       if (!Visited.insert(V).second)
7012         continue;
7013       if (Operator::getOpcode(V) == Instruction::IntToPtr) {
7014         const Value *O =
7015           getUnderlyingObjectFromInt(cast<User>(V)->getOperand(0));
7016         if (O->getType()->isPointerTy()) {
7017           Working.push_back(O);
7018           continue;
7019         }
7020       }
7021       // If getUnderlyingObjects fails to find an identifiable object,
7022       // getUnderlyingObjectsForCodeGen also fails for safety.
7023       if (!isIdentifiedObject(V)) {
7024         Objects.clear();
7025         return false;
7026       }
