6971 static const Value *getUnderlyingObjectFromInt(const Value *V) {
6972   do {
6973     if (const Operator *U = dyn_cast<Operator>(V)) {
6974       // If we find a ptrtoint, we can transfer control back to the
6975       // regular getUnderlyingObjectFromInt.
6976       if (U->getOpcode() == Instruction::PtrToInt)
6977         return U->getOperand(0);
6978       // If we find an add of a constant, a multiplied value, or a phi, it's
6979       // likely that the other operand will lead us to the base
6980       // object. We don't have to worry about the case where the
6981       // object address is somehow being computed by the multiply,
6982       // because our callers only care when the result is an
6983       // identifiable object.
6984       if (U->getOpcode() != Instruction::Add ||
6985           (!isa<ConstantInt>(U->getOperand(1)) &&
6986            Operator::getOpcode(U->getOperand(1)) != Instruction::Mul &&
6987            !isa<PHINode>(U->getOperand(1))))
6988         return V;
6989       V = U->getOperand(0);
6990     } else {
6991       return V;
6992     }
6993     assert(V->getType()->isIntegerTy() && "Unexpected operand type!");
6994   } while (true);
6995 }
